sp_widget.client_script:
function IncidentToProblemCtrl($scope, spUtil) {
    var c = this;
    c.searchQuery = '';
    c.searchResults = [];
    c.searchPerformed = false;
    c.searching = false;
    c.selectedIncident = null;
    c.isCreating = false;
    c.successMessage = null;
    c.errorMessage = null;
    c.createdProblemSysId = null;

    c.searchIncidents = function() {
        if (!c.searchQuery) return;
        c.searching = true;
        c.searchPerformed = true;
        c.selectedIncident = null;
        c.errorMessage = null;

        c.server.get({
            action: 'searchIncidents',
            query: c.searchQuery
        }).then(function(response) {
            c.searching = false;
            if (response.data) {
                c.searchResults = response.data.incidents || [];
            }
        }, function() {
            c.searching = false;
            c.errorMessage = 'Search failed. Please try again.';
        });
    };

    c.selectIncident = function(incident) {
        c.selectedIncident = incident;
        c.errorMessage = null;
    };

    c.createProblem = function() {
        if (!c.selectedIncident) return;
        c.isCreating = true;
        c.errorMessage = null;

        c.server.get({
            action: 'createProblem',
            incident_sys_id: c.selectedIncident.sys_id
        }).then(function(response) {
            c.isCreating = false;
            if (response.data && response.data.success) {
                c.successMessage = response.data.message;
                c.createdProblemSysId = response.data.sys_id;
                spUtil.publish('problem.created', {problemNumber: response.data.number});
            } else {
                c.errorMessage = response.data.error || 'Failed to create problem.';
            }
        }, function() {
            c.isCreating = false;
            c.errorMessage = 'An unexpected error occurred.';
        });
    };

    c.reset = function() {
        c.searchQuery = '';
        c.searchResults = [];
        c.searchPerformed = false;
        c.selectedIncident = null;
        c.successMessage = null;
        c.errorMessage = null;
        c.createdProblemSysId = null;
    };
}

sp_widget.css:
#incident-to-problem { max-width: 800px; margin: 0 auto; padding: 20px; font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif; }
.itsm-access-denied { max-width: 500px; margin: 40px auto; }
.itsm-problem-header { text-align: center; padding: 20px; background: linear-gradient(135deg, #6a1b9a 0%, #8e44ad 100%); color: white; border-radius: 8px; margin-bottom: 20px; box-shadow: 0 4px 15px rgba(0,0,0,0.1); }
.itsm-problem-header h2 { margin: 0 0 8px 0; font-size: 22px; font-weight: 300; }
.itsm-problem-header h2 .glyphicon { margin-right: 8px; }
.itsm-problem-header p { margin: 0; font-size: 13px; opacity: 0.9; }
.itsm-problem-form .panel { border: 1px solid #e0e0e0; border-radius: 6px; box-shadow: 0 2px 6px rgba(0,0,0,0.05); margin-bottom: 20px; }
.itsm-problem-form .panel-heading { background: #f8f9fa; border-bottom: 1px solid #e0e0e0; padding: 12px 15px; }
.itsm-problem-form .panel-title { font-size: 14px; font-weight: 600; color: #333; }
.itsm-problem-form .panel-title .glyphicon { margin-right: 8px; color: #8e44ad; }
.itsm-problem-form .panel-body { padding: 20px; }
.itsm-problem-form .form-control { border: 1px solid #ccc; border-radius: 4px; padding: 10px 12px; font-size: 14px; }
.itsm-problem-form .form-control:focus { border-color: #8e44ad; box-shadow: 0 0 0 2px rgba(142,68,173,0.2); }
.itsm-problem-form .list-group-item { border: 1px solid #e0e0e0; margin-bottom: 4px; border-radius: 4px !important; transition: all 0.2s ease; }
.itsm-problem-form .list-group-item:hover { background: #f3e5f5; border-color: #ce93d8; }
.itsm-problem-form .list-group-item.active { background: #8e44ad; border-color: #8e44ad; color: white; }
.itsm-problem-form .list-group-item.active .text-muted { color: #e1bee7 !important; }
.itsm-selected-incident .alert-info { border: 1px solid #ce93d8; background: #f3e5f5; color: #6a1b9a; border-radius: 6px; }
.itsm-problem-form ul { padding-left: 20px; }
.itsm-problem-form ul li { margin-bottom: 6px; color: #333; }
.btn-success { background: #8e44ad; border-color: #8e44ad; }
.btn-success:hover { background: #7b3a9e; border-color: #7b3a9e; }
.btn-primary { background: #8e44ad; border-color: #8e44ad; }
.btn-primary:hover { background: #7b3a9e; border-color: #7b3a9e; }
.itsm-problem-loading .spinner { width: 36px; height: 36px; border: 3px solid #f0f0f0; border-top: 3px solid #8e44ad; border-radius: 50%; animation: spin 1s linear infinite; display: inline-block; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

sp_widget.server_script:
(function() {
    data.isL2Agent = false;
    data.incidents = [];

    // Check if current user is L2 agent
    var pu = new ProblemUtils();
    data.isL2Agent = pu.isL2Agent();

    if (input && input.action) {
        switch (input.action) {
            case 'searchIncidents':
                var incidents = [];
                var query = input.query || '';

                if (query) {
                    var gr = new GlideRecord('incident');

                    // Search by number or short description
                    var encodedQuery = 'numberLIKE' + query + '^ORshort_descriptionLIKE' + query;

                    // L2 agents can see all incidents, not just their group's
                    gr.addEncodedQuery(encodedQuery);
                    gr.orderByDesc('sys_created_on');
                    gr.setLimit(20);
                    gr.query();

                    var stateLabels = {'1': 'New', '2': 'In Progress', '3': 'On Hold', '6': 'Resolved', '7': 'Closed'};

                    while (gr.next()) {
                        incidents.push({
                            sys_id: gr.getUniqueValue(),
                            number: gr.getValue('number'),
                            short_description: gr.getValue('short_description'),
                            category: gr.getDisplayValue('category'),
                            subcategory: gr.getDisplayValue('subcategory'),
                            state: gr.getValue('state'),
                            state_label: stateLabels[gr.getValue('state')] || 'Unknown',
                            caller_name: gr.getDisplayValue('caller_id'),
                            assignment_group_name: gr.getDisplayValue('assignment_group'),
                            urgency_label: {'1': 'High', '2': 'Medium', '3': 'Low'}[gr.getValue('urgency')] || 'Unknown'
                        });
                    }
                }

                data.incidents = incidents;
                break;

            case 'createProblem':
                var result = {};
                if (input.incident_sys_id) {
                    var incGr = new GlideRecord('incident');
                    if (incGr.get(input.incident_sys_id)) {
                        var problemUtil = new ProblemUtils();
                        result = problemUtil.createProblemFromIncident(incGr);
                    } else {
                        result = {success: false, error: 'Incident not found'};
                    }
                } else {
                    result = {success: false, error: 'No incident selected'};
                }
                data.success = result.success;
                data.message = result.message;
                data.number = result.number;
                data.sys_id = result.sys_id;
                data.error = result.error;
                break;
        }
    }
})();
